#!/usr/bin/env bash
set -euo pipefail

# Write/Upsert latest TW daily block into the ISO-week report and push.
# This script exists primarily for cron compatibility.
#
# Inputs expected (usually already generated by earlier cron steps):
# - tmp/tw-summary.md   (from bin/tw_make_summary.py)
# - tmp/tw-table.md     (from bin/tw_make_table.py)
# - tmp/tw-latest-date.txt (YYYY-MM-DD)

cd "$(dirname "$0")/.."

DATE="${1:-}"

# Default to *today in Asia/Taipei* to avoid stale tmp/tw-latest-date.txt causing
# the weekly file to be written under the wrong ISO week.
if [[ -z "${DATE}" ]]; then
  DATE="$(TZ=Asia/Taipei date +%F)"
fi

# If caller explicitly passes DATE, trust it.
# (We intentionally do NOT auto-read tmp/tw-latest-date.txt anymore.)

if [[ -z "${DATE}" ]]; then
  echo "missing DATE (pass YYYY-MM-DD)" >&2
  exit 2
fi

if [[ ! -s tmp/tw-summary.md ]]; then
  echo "missing tmp/tw-summary.md (run bin/tw_make_summary.py first)" >&2
  exit 2
fi
if [[ ! -s tmp/tw-table.md ]]; then
  echo "missing tmp/tw-table.md (run bin/tw_make_table.py first)" >&2
  exit 2
fi

YEAR="${DATE:0:4}"
WEEK="$(python3 - <<PY
import datetime as dt
print(dt.date.fromisoformat('${DATE}').isocalendar().week)
PY
)"
WFILE="reports/tw/${YEAR}-W$(printf '%02d' "${WEEK}").md"

BLOCK="/tmp/tw-daily-block-${DATE}.md"
cp tmp/tw-summary.md "${BLOCK}"
{
  echo
  echo "#### 追蹤清單（收盤）"
  echo
  cat tmp/tw-table.md
  echo
} >> "${BLOCK}"

python3 bin/md_upsert_daily_section.py --file "${WFILE}" --date "${DATE}" --content-file "${BLOCK}"
node bin/sync_reports.mjs

git add -A
git commit -m "TW weekly write ${DATE}" || true
git push
